class ModelOrchestrator extends EventEmitter {
    #isActive: boolean = false;
    #serverPort: number = 8100;
    #failedPings = 0;
    #pingsExecuted = 0;
    #anomalyMonitorTimer: NodeJS.Timeout | null = null;

    public get routerPort() { return this.#serverPort; }
    public get expertPort() { return this.#serverPort; }

    constructor() {
        super();
        const isNative = String(process.env.LIVA_USE_NATIVE).trim().toLowerCase() === "true";
        this.#serverPort = isNative ? 8100 : 8000;
    }

    public isReady() {
        return this.#isActive;
    }

    public async startSingleExpert(auth?: any): Promise<void> {
        logger.info(`[ModelOrchestrator] Decoupled Mode: Hardware Daemon is expected to be running on port ${this.#serverPort}`);
        this.#isActive = true;
    }

    public async killLlamaServer(): Promise<void> {
        // Managed by Hardware Daemon VRAMGuard automatically.
        logger.info(`[ModelOrchestrator] killLlamaServer requested, but hardware is managed externally by Daemon.`);
        this.#isActive = false;
    }

    public async restartRouter(): Promise<void> {
        logger.info(`[ModelOrchestrator] restartRouter requested. Awaiting Hardware Daemon self-healing...`);
        this.emit("rewarming_ai");
        this.#isActive = true;
    }

    public startAnomalyDetection() {
        if (this.#anomalyMonitorTimer) return;
        logger.info("🛡️ [DevSecOps] Tracking External AI Daemon Health...");
        
        this.#anomalyMonitorTimer = setInterval(async () => {
            if (this.#isActive && this.#serverPort) {
                const isNative = String(process.env.LIVA_USE_NATIVE).trim().toLowerCase() === "true";
                const targetPort = isNative ? 8100 : this.#serverPort;
                const targetUrl = isNative ? `http://127.0.0.1:${targetPort}/health` : `http://127.0.0.1:${targetPort}/v1/models`;

                this.#pingsExecuted++;
                if (this.#pingsExecuted <= 3) return; // Grace period

                try {
                    if (isNative) {
                        const { NativeIPCClient } = await import("../utils/NativeIPCClient");
                        const tempClient = new NativeIPCClient();
                        try {
                            const alive = await withSafeTimeout(tempClient.healthCheck(), 3000, "Native_HealthCheck_Timeout");
                            if (!alive) throw new Error("Native gRPC returned alive=false");
                        } finally {
                            tempClient.destroy();
                        }
                    } else {
                        await safeFetch(targetUrl, {}, 3000);
                    }
                    this.#failedPings = 0;
                    if (!this.#isActive) {
                        this.#isActive = true;
                        logger.info("🟢 [ModelOrchestrator] Hardware Daemon is ONLINE.");
                    }
                } catch (e: unknown) {
                    this.#failedPings++;
                    if (this.#failedPings >= 3) {
                        if (this.#isActive) {
                            logger.error("🛑 [DevSecOps] Hardware Daemon OFFLINE or VRAM Yielded. Circuit breaker activated.");
                            this.#isActive = false;
                            this.emit("anomaly_detected");
                        }
                        this.#failedPings = 0;
                    }
                }
            }
        }, 15000);
        this.#anomalyMonitorTimer.unref();
    }

    public getStatus() {
        return {
            routerActive: this.#isActive,
            routerPort: this.#serverPort,
            expertActive: this.#isActive,
            expertPort: this.#serverPort
        };
    }

    public async dispose() {
        if (this.#anomalyMonitorTimer) {
            clearInterval(this.#anomalyMonitorTimer);
            this.#anomalyMonitorTimer = null;
        }
        this.#isActive = false;
        this.removeAllListeners();
    }
}

constructor() {
        super();
        const isNative = String(process.env.LIVA_USE_NATIVE).trim().toLowerCase() === "true";
        this.#serverPort = isNative ? 8100 : 8000;
    }

public isReady() {
        return this.#isActive;
    }

public async startSingleExpert(auth?: any): Promise<void> {
        logger.info(`[ModelOrchestrator] Decoupled Mode: Hardware Daemon is expected to be running on port ${this.#serverPort}`);
        this.#isActive = true;
    }

public async killLlamaServer(): Promise<void> {
        // Managed by Hardware Daemon VRAMGuard automatically.
        logger.info(`[ModelOrchestrator] killLlamaServer requested, but hardware is managed externally by Daemon.`);
        this.#isActive = false;
    }

public async restartRouter(): Promise<void> {
        logger.info(`[ModelOrchestrator] restartRouter requested. Awaiting Hardware Daemon self-healing...`);
        this.emit("rewarming_ai");
        this.#isActive = true;
    }

public startAnomalyDetection() {
        if (this.#anomalyMonitorTimer) return;
        logger.info("🛡️ [DevSecOps] Tracking External AI Daemon Health...");
        
        this.#anomalyMonitorTimer = setInterval(async () => {
            if (this.#isActive && this.#serverPort) {
                const isNative = String(process.env.LIVA_USE_NATIVE).trim().toLowerCase() === "true";
                const targetPort = isNative ? 8100 : this.#serverPort;
                const targetUrl = isNative ? `http://127.0.0.1:${targetPort}/health` : `http://127.0.0.1:${targetPort}/v1/models`;

                this.#pingsExecuted++;
                if (this.#pingsExecuted <= 3) return; // Grace period

                try {
                    if (isNative) {
                        const { NativeIPCClient } = await import("../utils/NativeIPCClient");
                        const tempClient = new NativeIPCClient();
                        try {
                            const alive = await withSafeTimeout(tempClient.healthCheck(), 3000, "Native_HealthCheck_Timeout");
                            if (!alive) throw new Error("Native gRPC returned alive=false");
                        } finally {
                            tempClient.destroy();
                        }
                    } else {
                        await safeFetch(targetUrl, {}, 3000);
                    }
                    this.#failedPings = 0;
                    if (!this.#isActive) {
                        this.#isActive = true;
                        logger.info("🟢 [ModelOrchestrator] Hardware Daemon is ONLINE.");
                    }
                } catch (e: unknown) {
                    this.#failedPings++;
                    if (this.#failedPings >= 3) {
                        if (this.#isActive) {
                            logger.error("🛑 [DevSecOps] Hardware Daemon OFFLINE or VRAM Yielded. Circuit breaker activated.");
                            this.#isActive = false;
                            this.emit("anomaly_detected");
                        }
                        this.#failedPings = 0;
                    }
                }
            }
        }, 15000);
        this.#anomalyMonitorTimer.unref();
    }

public getStatus() {
        return {
            routerActive: this.#isActive,
            routerPort: this.#serverPort,
            expertActive: this.#isActive,
            expertPort: this.#serverPort
        };
    }

public async dispose() {
        if (this.#anomalyMonitorTimer) {
            clearInterval(this.#anomalyMonitorTimer);
            this.#anomalyMonitorTimer = null;
        }
        this.#isActive = false;
        this.removeAllListeners();
    }

class NLCommandTranslator {
    readonly #llm: OpenAI;
    readonly #modelName: string;

    constructor() {
        const AI_PROVIDER = process.env.AI_PROVIDER?.toLowerCase() || "local";
        const routerPort = process.env.ROUTER_PORT || 8000;
        
        this.#modelName = process.env.EXPERT_MODEL_NAME || "local-router";

        let defaultBaseUrl = `http://127.0.0.1:${routerPort}/v1`;
        let defaultApiKey = "liva-translator-token";
        /* istanbul ignore if */
        if (AI_PROVIDER === "cloud") {
            defaultBaseUrl = process.env.AI_BASE_URL || "";
            defaultApiKey = process.env.AI_API_KEY || "";
        }

        this.#llm = new OpenAI({
            baseURL: defaultBaseUrl,
            apiKey: defaultApiKey,
            timeout: 10000,
            maxRetries: 1,
        });
    }

    /**
     * Translates a natural language string into a structured IDE command.
     */
    public async translate(nlText: string, context?: string): Promise<TranslatedIDECommand> {
        try {
            const systemPrompt = `You are an expert IDE command translator.
Your job is to translate a user's natural language request into a specific IDE action.
Available Actions:
1. "open_file" (args: { filePath: string }) - User wants to open or view a file.
2. "run_terminal" (args: { command: string }) - User wants to run a shell/terminal command.
3. "insert_text" (args: { text: string }) - User wants to type or insert text into the active file.
4. "save_file" (args: {}) - User wants to save the current file.
5. "search_project" (args: { query: string }) - User wants to search for text across the project.
6. "unknown" (args: {}) - Cannot confidently map to any action.

${context ? `Current Context:\n${context}\n` : ""}
RESPOND ONLY WITH VALID JSON using this schema:
{
  "action": "open_file" | "run_terminal" | "insert_text" | "save_file" | "search_project" | "unknown",
  "args": { ... },
  "confidence": <number between 0 and 1>,
  "reasoning": "<brief explanation>"
}`;

            const response = await this.#llm.chat.completions.create({
                model: this.#modelName,
                messages: [
                    { role: "system", content: systemPrompt },
                    { role: "user", content: nlText }
                ],
                temperature: 0.1,
                response_format: { type: "json_object" }
            });

/* istanbul ignore next */
            const content = response.choices[0]?.message?.content || "{}";
            const parsed = JSON.parse(content) as TranslatedIDECommand;
            
            // Validate basic structure
            if (!parsed.action || typeof parsed.confidence !== "number") {
                return this.#createUnknownCommand("Invalid JSON structure from LLM");
            }

            logger.info(`[NLTranslator] Translated "${nlText}" -> ${parsed.action} (conf: ${parsed.confidence})`);
            return parsed;

        } catch (error: unknown) {
        const errMsg = error instanceof Error ? error.message : String(error);
            logger.error(`[NLTranslator] Translation failed: ${errMsg}`);
            return this.#createUnknownCommand(errMsg);
        }
    }

    #createUnknownCommand(reason: string): TranslatedIDECommand {
        return {
            action: "unknown",
            args: {},
            confidence: 0,
            reasoning: reason
        };
    }
}

