function loadEncryptionKey(): string {
    const envKey = process.env.LIVA_ENCRYPTION_KEY;
    if (!envKey) {
        const msg = "[EncryptionEngine] FATAL: LIVA_ENCRYPTION_KEY is not set. Cannot start without encryption key. Set a 32-byte key in your .env file.";
        logger.fatal(msg);
        throw new Error(msg);
    }
    if (Buffer.byteLength(envKey, "utf-8") !== AES_256_KEY_LENGTH) {
        const msg = `[EncryptionEngine] FATAL: LIVA_ENCRYPTION_KEY must be exactly ${AES_256_KEY_LENGTH} bytes for AES-256. Got ${Buffer.byteLength(envKey, "utf-8")} bytes.`;
        logger.fatal(msg);
        throw new Error(msg);
    }
    return envKey;
}

class EncryptionEngine {

    static #cachedKey: Buffer | null = null;

    static get #key(): Buffer {
        if (!this.#cachedKey) {
            this.#cachedKey = Buffer.from(loadEncryptionKey());
        }
        return this.#cachedKey;
    }

    /**
     * Encrypt plaintext using AES-256-GCM.
     * Output format: `<hex IV>:<hex AuthTag>:<hex ciphertext>`
     */
    static encrypt(text: string): string {
        const iv = crypto.randomBytes(IV_LENGTH);
        const cipher = crypto.createCipheriv("aes-256-gcm", this.#key, iv);
        let encrypted = cipher.update(text, "utf8", "hex");
        encrypted += cipher.final("hex");
        const authTag = cipher.getAuthTag().toString("hex");
        return `${iv.toString("hex")}:${authTag}:${encrypted}`;
    }

    /**
     * Decrypt AES-256-GCM ciphertext.
     * Returns raw text on failure or if input isn't in `iv:tag:cipher` format
     * (backward-compatible with pre-v4 plaintext data).
     */
    static decrypt(text: string): string {
        try {
            const parts = text.split(":");
            if (parts.length !== 3) return text; // Plain-text fallback
            const iv = Buffer.from(parts[0], "hex");
            const authTag = Buffer.from(parts[1], "hex");
            const encryptedText = parts[2];
            const decipher = crypto.createDecipheriv("aes-256-gcm", this.#key, iv);
            decipher.setAuthTag(authTag);
            let decrypted = decipher.update(encryptedText, "hex", "utf8");
            decrypted += decipher.final("utf8");
            return decrypted;
        } catch {
            return text; // Backward compat: return raw if decryption fails
        }
    }

    /**
     * Write encrypted content to a file using Atomic Write pattern.
     * Writes to `.tmp` first, then renames atomically to prevent corruption.
     */
    static async writeFileEncrypted(filePath: string, content: string): Promise<void> {
        const encrypted = EncryptionEngine.encrypt(content);
        const tmpPath = `${filePath}.tmp`;
        await fs.writeFile(tmpPath, encrypted, "utf-8");
        await safeRename(tmpPath, filePath);
    }

    /**
     * Read and decrypt a file. Returns empty string on failure.
     */
    static async readFileDecrypted(filePath: string): Promise<string> {
        try {
            const raw = await fs.readFile(filePath, "utf-8");
            return EncryptionEngine.decrypt(raw);
        } catch {
            return "";
        }
    }

    static async initFileEncrypted(filePath: string, defaultContent: string): Promise<void> {
        try {
            await fs.access(filePath);
        } catch {
            // File doesn't exist — create it
            await EncryptionEngine.writeFileEncrypted(filePath, defaultContent);
            logger.info(`[EncryptionEngine] Initialized encrypted file: ${filePath}`);
        }
    }

    /**
     * [Phase 5.1] Inversion of Control: Load Vault into ENV and immediately zero-fill the master key.
     */
    static loadVaultIntoEnv(): void {
        const encryptionKey = process.env.LIVA_ENCRYPTION_KEY;
        if (!encryptionKey || Buffer.byteLength(encryptionKey, 'utf8') !== AES_256_KEY_LENGTH) {
            console.error('[EncryptionEngine] LIVA_ENCRYPTION_KEY not set or invalid (must be 32 bytes). Cannot load vault.');
            return;
        }

        // Cache the key internally before wiping it from process.env
        if (!this.#cachedKey) {
            this.#cachedKey = Buffer.from(encryptionKey);
        }

        const vaultPath = process.env.LIVA_VAULT_PATH || path.join(process.cwd(), "..", "data", "liva_vault.json");

        if (syncFs.existsSync(vaultPath)) {
            try {
                const vaultData = JSON.parse(syncFs.readFileSync(vaultPath, "utf8"));
                let loadedCount = 0;

                for (const [key, encryptedValue] of Object.entries(vaultData)) {
                    if (typeof encryptedValue !== "string" || encryptedValue.length === 0) continue;
                    if (process.env[key]) continue; // explicit env takes precedence

                    try {
                        const decrypted = this.decrypt(encryptedValue);
                        if (decrypted && decrypted !== encryptedValue) { // Check if decryption succeeded
                            process.env[key] = decrypted;
                            loadedCount++;
                        }
                    } catch {
                        // Skip
                    }
                }

                if (loadedCount > 0) {
                    console.error(`[Vault] ✅ Đã giải mã an toàn ${loadedCount} keys từ ${vaultPath}`);
                }
            } catch (e) {
                console.error(`[Vault] Error reading vault at ${vaultPath}:`, e);
            }
        }

        // [Phase 5.1] Zero-Trust: Lập tức xóa sổ Master Key khỏi Memory (ENV) sau khi nạp Két Sắt!
        // Ngăn chặn các Memory Dump hoặc RCE lấy được chìa khóa chính.
        process.env.LIVA_ENCRYPTION_KEY = '';
        delete process.env.LIVA_ENCRYPTION_KEY;
    }
}

