public async speak(text: string): Promise<boolean> {
    try {
      // Gọi sang API của tiến trình Python với timeout 3000ms
      const res = await safeFetch("http://127.0.0.1:8002/tts", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text })
      }, 3000);

      if (res.ok) {
        const data = await res.json();
        if (data && data.audio) {
          this.emit("audio_base64", data.audio);
        }
        return true;
      } else {
        logger.warn({ context: "VoiceEngine" }, `Python TTS API trả về lỗi HTTP: ${res.status}`);
        return false;
      }
    } catch (e: unknown) {
      const errMsg = e instanceof Error ? ((e.cause instanceof Error ? e.cause.message : null) || e.message) : String(e);
      logger.warn({ err: errMsg, context: "VoiceEngine" }, "Không thể kết nối Python TTS");
      return false;
    }
  }

public pushTokens(token: string) {
    const sentence = this.#ttsFormatter.pushToken(token);
    if (sentence && sentence.trim().length > 0) {
      this.sendToVoicePy(sentence);
    }
  }

public flushTTS() {
    const remainder = this.#ttsFormatter.flush();
    if (remainder && remainder.trim().length > 0) {
      this.sendToVoicePy(remainder);
    }
  }

public preempt() {
    logger.warn(`[VoiceEngine] 🛑 Nhận lệnh Preempt! Dừng TTS.`);
    this.#ttsFormatter.reset();
    this.pendingTextQueue = []; // 🔒 [Memory Fix] Xả sạch hàng đợi khi bị ngắt lời
    if (this.ws && this.ws.readyState === WebSocket.OPEN) { // NOSONAR
      this.ws.send(JSON.stringify({ type: "interrupt" }));
    }
  }

public async destroy(): Promise<void> {
    logger.info(`[VoiceEngine] 🧹 Đang dọn dẹp tài nguyên...`);
    if (this.#reconnectTimer) {
      clearTimeout(this.#reconnectTimer);
      this.#reconnectTimer = null;
    }
    if (this.ws) {
      this.ws.removeAllListeners(); // Gỡ bỏ tất cả event listener trước khi đóng
      this.ws.close();
      this.ws = null;
    }
    this.pendingTextQueue = [];
    this.#ttsFormatter.reset();
    this.removeAllListeners();
  }

class VoiceRelayServer {
    private PYTHON_ENGINE_URL = 'ws://127.0.0.1:8002/ws';

    public start(port: number = 3000) {
        const app = express();
        const server = createServer(app);
        const wssUI = new WebSocketServer({ server });

        wssUI.on('connection', (uiSocket: WebSocket) => {
            logger.info('📱 [Voice Relay] Vue UI đã kết nối tới Cổng 3000');
            
            // Xây dựng cầu nối proxy tới Voice Engine
            const engineSocket = new WebSocket(this.PYTHON_ENGINE_URL);

            engineSocket.on('open', () => {
                logger.info('🧠 [Voice Relay] Bridge kết nối thành công với Liva Voice Engine (8002)');
            });

            // Luồng dữ liệu về: Voice Engine 8002 -> Vue UI 3000
            engineSocket.on('message', (data: WebSocket.RawData) => {
                if (uiSocket.readyState === WebSocket.OPEN) {
                    uiSocket.send(data.toString());
                }
            });

            // Luồng dữ liệu đi: Vue UI 3000 -> Voice Engine 8002
            uiSocket.on('message', (data: WebSocket.RawData) => {
                if (engineSocket.readyState === WebSocket.OPEN) {
                    engineSocket.send(data.toString());
                }
            });

            // Dọn dẹp connection khi client thoát
            uiSocket.on('close', () => {
                logger.info('📱 [Voice Relay] Vue UI đã ngắt kết nối');
                engineSocket.close();
            });
            
            engineSocket.on('close', () => uiSocket.close());
            engineSocket.on('error', (err) => logger.error(`[Voice Relay] Lỗi gọi Engine WS: ${err.message}`));
        });

        server.listen(port, () => {
            logger.info(`🚀 [Voice Relay] Listening at ws://localhost:${port}`);
        });
    }
}

