        await new Promise<void>((resolve, reject) => {
            const timer = setTimeout(() => {
                this.off("Page.loadEventFired", handler);
                reject(new Error(`[CDPClient] Page load timeout after ${timeoutMs}ms`));
            }, timeoutMs);

            const handler = () => {
                clearTimeout(timer);
                this.off("Page.loadEventFired", handler);
