async function scan(dir: string) {
    const files = await fsp.readdir(dir);
    for (const f of files) {
        const full = path.join(dir, f);
        if ((await fsp.stat(full)).isDirectory()) {
            if (f !== "node_modules" && f !== "dist") await scan(full);
        } else {
            // Lưới tàng hình (Bỏ qua file Rác/Test)
            if (f.startsWith("test_") || f.endsWith(".d.ts") || f.endsWith(".json")) continue;
            await extractSkeleton(full);
        }
    }
}

async function getGoogleAuthClient(): Promise<InstanceType<typeof google.auth.OAuth2>> {
  if (!fs.existsSync(CREDENTIALS_PATH)) {
    throw new Error(
      `[Google Auth] Không tìm thấy file credentials.json tại ${CREDENTIALS_PATH}. Vui lòng tạo trên Google Cloud Console.`,
    );
  }

  // 🔒 [Audit H-3] Async I/O — avoid blocking event loop
  const credentials = JSON.parse(await fsp.readFile(CREDENTIALS_PATH, "utf8"));

  // Nếu là file Service Account (chứa type="service_account")
  if (credentials.type === "service_account") {
    logger.info("[Google Auth] Đang sử dụng Service Account.");
    const auth = new google.auth.GoogleAuth({
      keyFile: CREDENTIALS_PATH,
      scopes: SCOPES,
    });
    return await auth.getClient() as InstanceType<typeof google.auth.OAuth2>;
  }

  // Nếu là file OAuth2 Desktop Client
  const { client_secret, client_id, redirect_uris } =
    credentials.installed || credentials.web;
  if (!client_secret || !client_id) {
    throw new Error("[Google Auth] File credentials.json không hợp lệ.");
  }

  const oAuth2Client = new google.auth.OAuth2(
    client_id,
    client_secret,
    redirect_uris[0],
  );

  // Check if we have previously stored a token.
  if (!fs.existsSync(TOKEN_PATH)) {
    throw new Error(
      `[Google Auth] Chưa được cấp quyền OAuth2 (Không tìm thấy token.json). Vui lòng chạy lệnh: npx tsx src/utils/auth_google_script.ts để đăng nhập lần đầu.`,
    );
  }

  // 🔒 [Audit H-3] Async I/O
  const token = JSON.parse(await fsp.readFile(TOKEN_PATH, "utf8"));
  oAuth2Client.setCredentials(token);

  // Auto-refresh token if needed
  oAuth2Client.on("tokens", (tokens) => {
    if (tokens.refresh_token) {
      // Modify token locally and save
      token.refresh_token = tokens.refresh_token;
    }
    token.access_token = tokens.access_token;
    // 🔒 [Audit H-3] Atomic Write: .tmp + rename to prevent token corruption
    const tmpPath = `${TOKEN_PATH}.tmp`;
    fsp.writeFile(tmpPath, JSON.stringify(token), "utf-8")
      .then(() => safeRename(tmpPath, TOKEN_PATH))
      .catch(e => logger.error(e, "[Google Auth] Atomic token save failed"));
    logger.info("[Google Auth] Đã làm mới token thành công.");
  });

  return oAuth2Client;
}

async function safeFetch(
    url: string,
    options: RequestInit = {},
    timeoutMs = 5000
): Promise<Response> {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

    // [Phase 2] OpenTelemetry: Inject TraceID into outbound requests
    const traceId = TraceContext.getTraceId();
    const headers = new Headers(options.headers || {});
    if (traceId !== "no-trace" && !headers.has("X-Trace-Id")) {
        headers.set("X-Trace-Id", traceId);
    }
    const finalOptions = { ...options, headers, signal: controller.signal };

    if (options.signal) {
        options.signal.addEventListener('abort', () => controller.abort(), { once: true });
    }

    try {
        const res = await fetch(url, finalOptions);

        if (!res.ok) {
            // Extract the actual API error message from the response body
            // (Replaces the lost axios `e.response.data` capability)
            const errorBody = await res.text().catch(() => "Unknown API Error");
            throw new Error(`HTTP ${res.status}: ${errorBody}`);
        }

        return res;
    } finally {
        clearTimeout(timeoutId);
    }
}

function withSafeTimeout<T>(
    promise: Promise<T>,
    ms: number,
    label = "TIMEOUT"
): Promise<T> {
    let timeoutId: ReturnType<typeof setTimeout>;

    const timeoutPromise = new Promise<never>((_, reject) => {
        timeoutId = setTimeout(() => reject(new Error(label)), ms);
    });

    return Promise.race([promise, timeoutPromise]).finally(() => {
        clearTimeout(timeoutId!);
    });
}

function safeExtractJSON<T>(text: string): T | null {
    const first = text.indexOf("{");
    const last = text.lastIndexOf("}");
    if (first === -1 || last === -1 || last < first) return null;
    try {
        const raw = text.substring(first, last + 1);
        return JSON.parse(jsonrepair(raw));
    } catch {
        return null;
    }
}

async function generateSmartFilename(topic: string, defaultName: string): Promise<string> {
    let shortName = defaultName;
    const currentSeal = livaEngine.getSeal();

    try {
        // Execute via the secure channel requiring the Engine Seal Token
        const resName = await livaEngine.secureChatCompletion<any>(
            {
                model: "expert",
                messages: [{ 
                    role: "user", 
                    content: `Hành động như một bot đổi tên file. Rút gọn cụm từ/chủ đề sau thành 1 tên file tiếng Anh ngắn gọn, súc tích (tối đa 4 từ, nối bằng gạch dưới _). VÍ DỤ: "Báo cáo doanh số quý 1" -> "q1_revenue_report". Tương tự hãy làm với Chủ đề: "${topic}". CHỈ TRẢ VỀ DUY NHẤT TÊN FILE (không giải thích, không in ký tự lạ).` 
                }],
                temperature: 0.1,
                max_tokens: 20
            },
            currentSeal
        );

        const aiName = resName.choices[0]?.message?.content?.trim();

        if (aiName) {
            // Clean the output to ensure it adheres to filename standards
            if (!aiName.includes(" ")) {
                shortName = aiName.replaceAll(/[^\w-]/g, "").toLowerCase();
            } else {
                shortName = aiName.replaceAll(/[^\w-]/g, "_").replaceAll(/_+/g, "_").toLowerCase();
            }
        }
    } catch (e: unknown) {
    const errMsg = e instanceof Error ? e.message : String(e);
        // Handle security violations or network errors separately
        if (errMsg.includes("SECURITY VIOLATION")) {
            logger.error(`[LivaEngine] CRITICAL SECURITY ALERT: ${errMsg}`);
        } else {
            logger.error(`[LivaEngine] Smart Naming Error: ${errMsg}`);
        }
    }

    return shortName;
}

