        this.l2Latencies.push(ms);
        if (ms > this.l2MaxLatency) this.l2MaxLatency = ms;
        // Keep only last 100 samples for moving average
        if (this.l2Latencies.length > 100) {
            this.l2Latencies.shift();
        }
